import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ViewState = 'works' | 'about';

export interface WorkItem {
  id: number;
  title: string;
  icon: string;
  bgColor: string;
}

import React, { useState, useEffect } from 'react';
import { ViewState } from './types';
import Header from './components/Header';
import Works from './components/Works';
import About from './components/About';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('works');
  const [isVisible, setIsVisible] = useState(false);

  // Simple entry animation
  useEffect(() => {
    setIsVisible(true);
  }, []);

  // Handle smooth transition between views
  const handleViewChange = (newView: ViewState) => {
    if (newView === view) return;
    setIsVisible(false);
    setTimeout(() => {
      setView(newView);
      setIsVisible(true);
    }, 300);
  };

  return (
    <div className="min-h-screen max-w-5xl mx-auto px-6 py-12 md:py-20 flex flex-col items-center">
      <Header currentView={view} onViewChange={handleViewChange} />

      <main className={`w-full transition-all duration-500 ease-in-out ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
        {view === 'works' ? <Works /> : <About />}
      </main>

      <footer className="mt-auto pt-20 pb-10 text-xs text-gray-400 font-light tracking-widest uppercase">
        © {new Date().getFullYear()} Rowan Li. All Rights Reserved.
      </footer>
    </div>
  );
};

export default App;

