export type ViewState = 'works' | 'about' | 'practice' | 'competition' | 'project-detail' | 'base-solution' | 'ai-exploration' | 'visual-creative';

export interface WorkItem {
  id: number;
  title: string;
  icon: string;
  bgColor: string;
